class Solution:
    def maxSumBST(self, root):
        if root is None:
            return 0
        info = {}
        best = [0]
        stack = [(root, False)]
        NEG_INF = float('-inf')
        POS_INF = float('inf')
        while stack:
            node, visited = stack.pop()
            if visited:
                l = info.get(node.left, (True, POS_INF, NEG_INF, 0))
                r = info.get(node.right, (True, POS_INF, NEG_INF, 0))
                l_ok, l_min, l_max, l_sum = l
                r_ok, r_min, r_max, r_sum = r
                if l_ok and r_ok and l_max < node.val < r_min:
                    total = l_sum + r_sum + node.val
                    if total > best[0]:
                        best[0] = total
                    info[node] = (True, min(l_min, node.val), max(r_max, node.val), total)
                else:
                    info[node] = (False, 0, 0, 0)
            else:
                stack.append((node, True))
                if node.left:
                    stack.append((node.left, False))
                if node.right:
                    stack.append((node.right, False))
        return best[0]

