var maxSumBST = function(root) {
    let best = 0;
    function dfs(node) {
        if (!node) return [true, Infinity, -Infinity, 0];
        const [lOk, lMin, lMax, lSum] = dfs(node.left);
        const [rOk, rMin, rMax, rSum] = dfs(node.right);
        if (lOk && rOk && lMax < node.val && node.val < rMin) {
            const total = lSum + rSum + node.val;
            if (total > best) best = total;
            return [true, Math.min(lMin, node.val), Math.max(rMax, node.val), total];
        }
        return [false, 0, 0, 0];
    }
    dfs(root);
    return best;
};
